from marshmallow import Schema, fields, validates, ValidationError


class Bar(Schema):
    value = fields.String()

    @validates('value')
    def validate_value(self, value):
        if value == 'bad':
            raise ValidationError('Value cannot be "bad"')
        return value


class Foo(Schema):
    bar = fields.Nested(Bar)


sch = Foo()

print("Test 1: Valid nested object")
try:
    result = sch.validate({
        'bar': {'value': 'good'},
    })
    print("Validation result:", result)
except Exception as e:
    print(f"Error occurred: {type(e).__name__}: {e}")

print("\nTest 2: Invalid nested object (string instead of dict)")
try:
    result = sch.validate({
        'bar': 'invalid',
    })
    print("Validation result:", result)
