from marshmallow import Schema, fields, validates, ValidationError

print("=== Test 1: Original issue from PR ===")
class Bar(Schema):
    value = fields.String()

    @validates('value')
    def validate_value(self, value):
        pass

class Foo(Schema):
    bar = fields.Nested(Bar)

sch = Foo()
result = sch.validate({'bar': 'invalid'})
print(f"Result: {result}")
assert result == {'bar': {'_schema': ['Invalid input type.']}}

print("\n=== Test 2: Nested with many=True ===")
class Item(Schema):
    id = fields.Integer()

    @validates('id')
    def validate_id(self, value):
        if value < 0:
            raise ValidationError("ID must be positive")

class Collection(Schema):
    items = fields.Nested(Item, many=True)

coll = Collection()
result = coll.validate({'items': [{'id': 1}, 'invalid', {'id': -1}]})
print(f"Result: {result}")
# Should have error for index 1 (invalid type) and index 2 (negative id)

print("\n=== Test 3: Schema-level validator with nested error ===")
class MySchema(Schema):
    data = fields.Nested(Bar)

    @validates_schema
    def validate_schema(self, data):
        # This should not crash even if nested validation failed
        pass

mysch = MySchema()
result = mysch.validate({'data': 'invalid'})
print(f"Result: {result}")
assert 'data' in result

print("\n=== Test 4: Multiple validators ===")
class MultiValidatorSchema(Schema):
    field1 = fields.String()
    field2 = fields.Integer()

    @validates('field1')
    def validate_field1(self, value):
        if not value:
            raise ValidationError("field1 cannot be empty")

    @validates('field2')
    def validate_field2(self, value):
        if value > 100:
            raise ValidationError("field2 too large")

multisch = MultiValidatorSchema()
result = multisch.validate({'field1': '', 'field2': 200})
print(f"Result: {result}")
assert 'field1' in result and 'field2' in result

print("\n=== All tests passed! ===")
EOF"}

